// ServerInterface represents all server handlers.
type ServerInterface interface {
	// List collector agents (gateway replicas and edge agents)
	// (GET /api/v1/agents)
	ListAgents(w http.ResponseWriter, r *http.Request, params ListAgentsParams)
	// Forget a stale agent (a reconnecting agent re-registers itself)
	// (DELETE /api/v1/agents/{agentId})
	DeleteAgent(w http.ResponseWriter, r *http.Request, agentId openapi_types.UUID)
	// Get one agent including its health tree
	// (GET /api/v1/agents/{agentId})
	GetAgent(w http.ResponseWriter, r *http.Request, agentId openapi_types.UUID)
	// Assigned (desired) and reported (effective) config for the diff view
	// (GET /api/v1/agents/{agentId}/config)
	GetAgentConfig(w http.ResponseWriter, r *http.Request, agentId openapi_types.UUID)
	// Status transitions of one agent, newest first
	// (GET /api/v1/agents/{agentId}/events)
	ListAgentEvents(w http.ResponseWriter, r *http.Request, agentId openapi_types.UUID, params ListAgentEventsParams)
	// Query the audit log (newest first, cursor-paged)
	// (GET /api/v1/audit)
	ListAuditLog(w http.ResponseWriter, r *http.Request, params ListAuditLogParams)
	// Password-less local development login (disabled in production)
	// (POST /api/v1/auth/dev-login)
	DevLogin(w http.ResponseWriter, r *http.Request)
	// Destroy the current session
	// (POST /api/v1/auth/logout)
	Logout(w http.ResponseWriter, r *http.Request)
	// Configured SSO providers for the login page (public)
	// (GET /api/v1/auth/providers)
	ListAuthProviders(w http.ResponseWriter, r *http.Request)
	// Curated collector components available in the pipeline builder
	// (GET /api/v1/catalog/components)
	GetComponentCatalog(w http.ResponseWriter, r *http.Request)
	// List customers
	// (GET /api/v1/customers)
	ListCustomers(w http.ResponseWriter, r *http.Request, params ListCustomersParams)
	// Create a customer (generates client ID and an initial API key)
	// (POST /api/v1/customers)
	CreateCustomer(w http.ResponseWriter, r *http.Request)
	// Soft-delete a customer (revokes all API keys)
	// (DELETE /api/v1/customers/{customerId})
	DeleteCustomer(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// Get a customer
	// (GET /api/v1/customers/{customerId})
	GetCustomer(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// Update name or status
	// (PATCH /api/v1/customers/{customerId})
	UpdateCustomer(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// List API keys of a customer (never includes secrets)
	// (GET /api/v1/customers/{customerId}/api-keys)
	ListApiKeys(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// Create an API key (secret returned exactly once)
	// (POST /api/v1/customers/{customerId}/api-keys)
	CreateApiKey(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// Revoke an API key (takes effect at the gateway within ~60s)
	// (DELETE /api/v1/customers/{customerId}/api-keys/{keyId})
	RevokeApiKey(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID, keyId openapi_types.UUID)
	// List edge-agent enrollment tokens (never includes secrets)
	// (GET /api/v1/customers/{customerId}/bootstrap-tokens)
	ListBootstrapTokens(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// Create an enrollment token (secret returned exactly once)
	// (POST /api/v1/customers/{customerId}/bootstrap-tokens)
	CreateBootstrapToken(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// Revoke an enrollment token (existing agents stay connected)
	// (DELETE /api/v1/customers/{customerId}/bootstrap-tokens/{tokenId})
	RevokeBootstrapToken(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID, tokenId openapi_types.UUID)
	// List pipelines of a customer
	// (GET /api/v1/customers/{customerId}/pipelines)
	ListCustomerPipelines(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// Create a pipeline with an initial draft version
	// (POST /api/v1/customers/{customerId}/pipelines)
	CreatePipeline(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID)
	// Per-signal ingest time series for one customer
	// (GET /api/v1/customers/{customerId}/stats/throughput)
	GetCustomerThroughput(w http.ResponseWriter, r *http.Request, customerId openapi_types.UUID, params GetCustomerThroughputParams)
	// Current session user, role and CSRF token
	// (GET /api/v1/me)
	GetMe(w http.ResponseWriter, r *http.Request)
	// List all pipelines across customers
	// (GET /api/v1/pipelines)
	ListPipelines(w http.ResponseWriter, r *http.Request)
	// Validate a pipeline graph (structural + real `otelcol validate`)
	// (POST /api/v1/pipelines/validate)
	ValidatePipeline(w http.ResponseWriter, r *http.Request)
	// Delete a pipeline (removes it from the forwarding config on next rollout)
	// (DELETE /api/v1/pipelines/{pipelineId})
	DeletePipeline(w http.ResponseWriter, r *http.Request, pipelineId openapi_types.UUID)
	// Get a pipeline including its versions
	// (GET /api/v1/pipelines/{pipelineId})
	GetPipeline(w http.ResponseWriter, r *http.Request, pipelineId openapi_types.UUID)
	// Per-stage flow metrics for a pipeline (received/exported/failed/queued)
	// (GET /api/v1/pipelines/{pipelineId}/stats/stages)
	GetPipelineStageStats(w http.ResponseWriter, r *http.Request, pipelineId openapi_types.UUID, params GetPipelineStageStatsParams)
	// Create a new version from a graph (validated; rejected when invalid)
	// (POST /api/v1/pipelines/{pipelineId}/versions)
	CreatePipelineVersion(w http.ResponseWriter, r *http.Request, pipelineId openapi_types.UUID)
	// Get one version including rendered YAML
	// (GET /api/v1/pipelines/{pipelineId}/versions/{version})
	GetPipelineVersion(w http.ResponseWriter, r *http.Request, pipelineId openapi_types.UUID, version int)
	// Activate a version (deploys it to the forwarding tier; also used for rollback)
	// (POST /api/v1/pipelines/{pipelineId}/versions/{version}/activate)
	ActivatePipelineVersion(w http.ResponseWriter, r *http.Request, pipelineId openapi_types.UUID, version int)
	// Configured SSO providers incl. env-defined ones (admin only, no secrets)
	// (GET /api/v1/settings/auth-providers)
	ListAuthProviderConfigs(w http.ResponseWriter, r *http.Request)
	// Add an SSO provider (client secret is encrypted at rest)
	// (POST /api/v1/settings/auth-providers)
	CreateAuthProviderConfig(w http.ResponseWriter, r *http.Request)
	// Remove a provider (existing sessions stay valid)
	// (DELETE /api/v1/settings/auth-providers/{providerId})
	DeleteAuthProviderConfig(w http.ResponseWriter, r *http.Request, providerId openapi_types.UUID)
	// Update a provider; omit clientSecret to keep the stored one
	// (PATCH /api/v1/settings/auth-providers/{providerId})
	UpdateAuthProviderConfig(w http.ResponseWriter, r *http.Request, providerId openapi_types.UUID)
	// Connectivity test (OIDC discovery / GitHub API reachability)
	// (POST /api/v1/settings/auth-providers/{providerId}/test)
	TestAuthProviderConfig(w http.ResponseWriter, r *http.Request, providerId openapi_types.UUID)
	// Fleet-wide totals for the dashboard
	// (GET /api/v1/stats/overview)
	GetStatsOverview(w http.ResponseWriter, r *http.Request, params GetStatsOverviewParams)
	// List UI users (admin only)
	// (GET /api/v1/users)
	ListUsers(w http.ResponseWriter, r *http.Request)
	// Invite a user by email; the role applies on their first SSO login
	// (POST /api/v1/users)
	InviteUser(w http.ResponseWriter, r *http.Request)
	// Delete a user (admin only, not self, not the last admin)
	// (DELETE /api/v1/users/{userId})
	DeleteUser(w http.ResponseWriter, r *http.Request, userId openapi_types.UUID)
	// Change role or disable/enable (admin only; self-demotion and disabling the last admin are rejected)
	// (PATCH /api/v1/users/{userId})
	UpdateUser(w http.ResponseWriter, r *http.Request, userId openapi_types.UUID)
}

